#include <iostream>
#include <sstream>

// Assume Vector2D class and operator<< are defined here
// For testing, we need a correct version of Vector2D and operator<<
class Vector2D {
private:
    double x;
    double y;

public:
    Vector2D(double x_val, double y_val) : x(x_val), y(y_val) {}

    friend std::ostream& operator<<(std::ostream& os, const Vector2D& v) {
        os << "(" << v.x << ", " << v.y << ")";
        return os;
    }
};

int main() {
    std::stringstream ss;
    Vector2D v1(1.0, 2.5);
    Vector2D v2(-3.0, 0.0);

    ss << "Vector 1: " << v1 << std::endl;
    ss << "Vector 2: " << v2 << std::endl;

    std::cout << ss.str();
    return 0;
}
